import{_ as o,o as r,c as n,ae as i}from"./chunks/framework.DHedrh8w.js";const h=JSON.parse('{"title":"零基础：用 AI 制作你的“物流数据自动叉车”","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials/tech_prompt.md","filePath":"tutorials/tech_prompt.md"}'),a={name:"tutorials/tech_prompt.md"};function s(l,t,e,g,c,p){return r(),n("div",null,[...t[0]||(t[0]=[i('<h1 id="零基础-用-ai-制作你的-物流数据自动叉车" tabindex="-1"><strong>零基础：用 AI 制作你的“物流数据自动叉车”</strong> <a class="header-anchor" href="#零基础-用-ai-制作你的-物流数据自动叉车" aria-label="Permalink to &quot;**零基础：用 AI 制作你的“物流数据自动叉车”**&quot;">​</a></h1><p>本教程专为美西仓储物流行业办公人员设计。我们将制作一个插件，它能在网页表格上自动浮现一个“下载”图标，点击即可导出 CSV。</p><h2 id="_1-核心概念-物流人的类比理解" tabindex="-1"><strong>1. 核心概念：物流人的类比理解</strong> <a class="header-anchor" href="#_1-核心概念-物流人的类比理解" aria-label="Permalink to &quot;**1\\. 核心概念：物流人的类比理解**&quot;">​</a></h2><ul><li><strong>Manifest (提单/BOL)</strong>：插件的身份证明，告诉浏览器这个货是谁的，有哪些权限。</li><li><strong>Content Script (仓库操作员)</strong>：它驻扎在网页里，负责扫描网页上的表格（货物），并贴上“下载”标签。</li><li><strong>CSV (集装箱)</strong>：把散乱的网页数据打包成标准格式。</li></ul><h2 id="_2-向-ai-antigravity-下达指令" tabindex="-1"><strong>2. 向 AI (Antigravity) 下达指令</strong> <a class="header-anchor" href="#_2-向-ai-antigravity-下达指令" aria-label="Permalink to &quot;**2\\. 向 AI (Antigravity) 下达指令**&quot;">​</a></h2><p>复制以下这段 <strong>Prompt (提示词)</strong> 发送给 AI 助手：</p><p><strong>角色：</strong> 你是一位 Chrome 插件开发专家。</p><p><strong>任务：</strong> 帮我编写一个 Manifest V3 版本的插件。</p><p><strong>行业背景：</strong> 针对物流仓储 WMS 系统的网页表格提取。</p><p><strong>功能逻辑：</strong></p><ol><li><strong>自动识别：</strong> 扫描当前网页中所有的 &lt;table&gt; 标签。</li><li><strong>浮动工具栏：</strong> 在每个表格的上部，自动生成悬浮的一组按钮：一个是绿色的“导出 Excel (CSV)”按钮，另一个是红色的“关闭”按钮（×）。</li><li><strong>关闭逻辑：</strong> 用户点击“关闭”按钮后，立即隐藏该表格对应的这组工具栏，且在用户刷新或重新打开页面前，不再为该表格显示这两组图标。</li><li><strong>数据处理：</strong> 当用户点击导出按钮时，提取该表格内的所有行（tr）和列（td），忽略 HTML 标签，仅保留纯文本。</li><li><strong>触发下载：</strong> 将提取的数据转换成 CSV 格式，并以“Logistics_Data_当前日期.csv”为文件名自动触发浏览器下载。</li><li><strong>样式要求：</strong> 悬浮按钮要使用现代物流绿与关闭红配色，显眼但不遮挡表格内容，使用 flex 布局排列。<br><strong>输出：</strong> 请直接给我 manifest.json 和 content.js 两个文件的代码。</li></ol><h2 id="_3-本地部署-开发者模式" tabindex="-1"><strong>3. 本地部署（开发者模式）</strong> <a class="header-anchor" href="#_3-本地部署-开发者模式" aria-label="Permalink to &quot;**3\\. 本地部署（开发者模式）**&quot;">​</a></h2><p>当你拿到 AI 生成的代码后，请执行以下步骤：</p><ol><li><strong>创建文件夹</strong>：在桌面新建一个文件夹，命名为 Logistics_Table_Tool。</li><li><strong>保存文件</strong>： <ul><li>将 AI 提供的第一段代码存为 manifest.json。</li><li>将 AI 提供的第二段代码存为 content.js。</li><li><em>(注：确保文件名后缀准确，不要存成 .txt)</em></li></ul></li><li><strong>加载插件</strong>： <ul><li>打开 Chrome 浏览器，访问 chrome://extensions/。</li><li>开启右上角的 <strong>“开发者模式” (Developer mode)</strong>。</li><li>点击左上角的 <strong>“加载已解压的扩展程序” (Load unpacked)</strong>。</li><li>选择你刚才创建的 Logistics_Table_Tool 文件夹。</li></ul></li></ol><h2 id="_4-行业应用测试" tabindex="-1"><strong>4. 行业应用测试</strong> <a class="header-anchor" href="#_4-行业应用测试" aria-label="Permalink to &quot;**4\\. 行业应用测试**&quot;">​</a></h2><p>去你的 WMS 系统（如 HighJump, NetSuite, 或 Amazon 后台）刷新页面。你会发现每个表格上方都出现了一个下载按钮。</p><h2 id="_5-进阶-如何-打包-发给同事" tabindex="-1"><strong>5. 进阶：如何“打包”发给同事？</strong> <a class="header-anchor" href="#_5-进阶-如何-打包-发给同事" aria-label="Permalink to &quot;**5\\. 进阶：如何“打包”发给同事？**&quot;">​</a></h2><ol><li>在插件管理页面点击 <strong>“打包扩展程序” (Pack extension)</strong>。</li><li>浏览器会生成一个 .crx 文件（插件实体）和一个 .pem 文件（密钥）。</li><li>你可以把 .crx 发给同事，让他们拖进浏览器即可安装（需开启开发者模式）。</li></ol>',18)])])}const d=o(a,[["render",s]]);export{h as __pageData,d as default};
